COMMENT "Hallow用户账户信息视图" AS SELECT '2311' AS `product_id`, `ods`.`a1`.`Id`, `ods`.`a1`.`Account`, `ods`.`a1`.`Nick`, `ods`.`a1`.`Sex`, `ods`.`a1`.`CreateTime` AS `create_time`, `ods`.`a1`.`LastLoginTime` AS `last_login_time`, datediff(`ods`.`a1`.`LastLoginTime`, `ods`.`a1`.`CreateTime`) AS `last_login_creation_delta`, `ods`.`a1`.`LastActiveTime` AS `last_active_time`, `ods`.`a1`.`Chl`, `ods`.`a1`.`Chl2`, `ods`.`a1`.`Mt`, `ods`.`a1`.`Mt2`, `ods`.`a1`.`CurrentLanguage` AS `current_language`, `ods`.`a1`.`CurrentLanguage2` AS `current_language2`, `ods`.`a1`.`CoreVer` AS `core_ver`, `ods`.`a1`.`CoreVer2` AS `core_ver2`, `ods`.`a1`.`UniqueCdReaderId` AS `unique_cd_reader_id`, `ods`.`a1`.`Country`, `ods`.`a1`.`RegCountry` AS `reg_country`, `ods`.`a1`.`Ver`, `ods`.`a1`.`Avatar`, `ods`.`a1`.`Appver`, `ods`.`a1`.`Ip`, `ods`.`a1`.`RegIp` AS `reg_ip`, `ods`.`a1`.`UtcOffset` AS `utc_offset`, `ods`.`a1`.`CurrentBookId` AS `current_book_id`, `ods`.`a1`.`EMail`, `ods`.`a1`.`IsDeleted` AS `is_deleted`, `ods`.`a1`.`VipExpireTime` AS `vip_expire_time`, `ods`.`a1`.`row_update_time`, `ods`.`a1`.`FirstOpenResId` AS `first_open_res_id`, `ods`.`a1`.`IMSI`, `ods`.`a2`.`SourceChl` AS `source_chl`, `ods`.`a1`.`ADID` AS `ad_id`, `ods`.`a1`.`LastInstallTime` AS `last_install_time`, `ods`.`a1`.`LastDayActiveTime` AS `last_day_active_time`, `ods`.`a1`.`BeforeLastActiveTime` AS `before_last_active_time`, `ods`.`a1`.`FirstOpenResId` AS `_first_open_res_id`, `ods`.`a1`.`IMSI` AS `_i_m_s_i`, `ods`.`a2`.`SourceChl` AS `_source_chl`, `ods`.`a1`.`ADID` AS `_a_d_i_d`, `ods`.`a1`.`LastInstallTime` AS `_last_install_time`, `ods`.`a1`.`LastDayActiveTime` AS `_last_day_active_time`, `ods`.`a1`.`BeforeLastActiveTime` AS `_before_last_active_time`, `ods`.`a2`.`ConversationId` AS `conversation_id`, `ods`.`a2`.`RemarketingTime` AS `remarketing_time`, `ods`.`a2`.`AttributionDropTime` AS `attribution_drop_time`, `ods`.`a2`.`AdSetName` AS `ad_set_name`, `ods`.`a2`.`AdSetId` AS `ad_set_id`, `ods`.`a2`.`AdCampId` AS `ad_camp_id`, `ods`.`a2`.`AdCampName` AS `ad_camp_name`, `ods`.`a2`.`IsRemarketing` AS `is_remarketing`, `ods`.`a2`.`DynamicIslandSwitch` AS `dynamic_island_switch`, `ods`.`a2`.`LastCourseId` AS `last_course_id`, `ods`.`a2`.`WeekChargePlanPrice` AS `week_charge_plan_price`, `ods`.`a2`.`HasCharge` AS `has_charge`, `ods`.`a2`.`FirstChargeAmount` AS `first_charge_amount`, `ods`.`a2`.`TotalChargeAmount` AS `total_charge_amount`, `ods`.`a2`.`LastChargeAmount` AS `last_charge_amount`, `ods`.`a2`.`AdverUnlockCount` AS `adver_unlock_count`, `ods`.`a2`.`FirstECPMReportValue` AS `first_ecpm_report_value`, `ods`.`a2`.`LastECPMReportValue` AS `last_ecpm_report_value`, `ods`.`a2`.`AdPreloadReportNum` AS `ad_preload_report_num`, `ods`.`a2`.`AdPreloadResetTime` AS `ad_preload_reset_time`, `ods`.`a2`.`AskTheBibleUnreadMessage` AS `ask_the_bible_unread_message`, `ods`.`a2`.`BibleJoyUnreadMessage` AS `bible_joy_unread_message`, `ods`.`a1`.`sr_createtime`, `ods`.`a1`.`sr_updatetime`
